              aria-invalid={Boolean(tokenFieldError)}
            />
            <AuthFieldError message={tokenFieldError ?? undefined} />
          </div>
        ) : null}
        <AuthTextField
          id="newPassword"
          label="New password (min 8 characters)"
          type="password"
          autoComplete="new-password"
          aria-invalid={Boolean(errors.newPassword)}
          {...register("newPassword")}
        />
        <AuthFieldError message={errors.newPassword?.message} />
        <AuthTextField
          id="confirm"
          label="Confirm password"
          type="password"
          autoComplete="new-password"
          aria-invalid={Boolean(errors.confirm)}
          {...register("confirm")}
        />
        <AuthFieldError message={errors.confirm?.message} />
        {error ? <AuthFieldError message={error} /> : null}
        <Button type="submit" className="w-full" disabled={isSubmitting}>
          {isSubmitting ? "Updating…" : "Update password"}
        </Button>
      </form>
      <nav className="flex flex-col gap-2 text-center text-sm text-muted-foreground" aria-label="Account recovery">
        <Link href="/forgot-password" className="underline underline-offset-4">
          Request a new reset link
        </Link>
        <Link href="/login" className="underline underline-offset-4">
          Back to sign in
        </Link>
      </nav>
    </section>
  );
}

